VALUES
  ('fire-eq-eng-moex-00923', 'fire-eq-eng', 'fire-eq-eng-moex-100-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據消防設備師及消防設備士管理辦法，消防設備師自取得證書日起每三年應接受講習一次或取得累計 積分之訓練證明文件，訓練證明文件取得之積分何者說明為正確？', '["中央主管機關舉辦或認可之講習會、研討會或專題演講，每小時積分十分", "消防專技人員公會或全國聯合會之年會及當次達一小時以上之技術研討會，每次積分十分", "中央主管機關舉辦或認可之專業訓練課程，每小時積分二十分", "於國外參加專業機構或團體舉辦國際性之講習會、研討會或專題演講領有證明文件者，每小時積分二十分"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "83e46321b1e9", "answer_pdf_sha1": "7beed2e47fef", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00924', 'fire-eq-eng', 'fire-eq-eng-moex-100-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法之規定，有關儲存鍋爐油之室內儲槽場所其 位置、構造及設備應符合項目及說明何者不正確？', '["鍋爐油屬第四類易燃液體之第三石油類", "儲槽容量不得超過管制量之四十倍，儲存數量不得超過二萬五千公升", "儲槽專用室之儲槽與室內牆面之距離應在五十公分以上", "儲槽材質應為厚度三點二公釐以上之鋼板或具有同等以上性能者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "83e46321b1e9", "answer_pdf_sha1": "7beed2e47fef", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00925', 'fire-eq-eng', 'fire-eq-eng-moex-100-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '使用液化石油氣容器連接燃氣設施之場所，使用量在一百二十公斤以上未滿三百公斤者，依據「公共危 險物品及可燃性高壓氣體設置標準暨安全管理辦法」之規定，容器與用火設備最短距離限制為何？', '["0.5公尺以上", "1公尺以上", "1.5公尺以上", "2公尺以上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "83e46321b1e9", "answer_pdf_sha1": "7beed2e47fef", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00926', 'fire-eq-eng', 'fire-eq-eng-moex-100-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據消防機具器材及設備認可作業要點之規定，型式認可之有效期限為何？期限屆滿前得申請延期，每 次可延期期間為何？', '["三年、三年", "三年、五年", "五年、三年", "五年、五年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "83e46321b1e9", "answer_pdf_sha1": "7beed2e47fef", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00927', 'fire-eq-eng', 'fire-eq-eng-moex-100-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據可燃性高壓氣體儲存場所防爆牆設置基準，下列規定何者為正確？', '["鋼筋混凝土經過二十八日養生後之抗壓強度210 kgf/cm2 以上", "防爆牆分為鋼筋混凝土製及鋼板製二種", "防爆牆牆腳與儲存場所建築物之距離不得少於1.5公尺", "防爆牆之端部或隙角部分須用直徑 13 mm以上鋼筋"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "83e46321b1e9", "answer_pdf_sha1": "7beed2e47fef", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00928', 'fire-eq-eng', 'fire-eq-eng-moex-100-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據防焰性能試驗基準規定，防焰物品或其材料之防焰性能對於餘焰時間之規定，下列何者為正確？', '["地毯等地坪舖設物類不得超過二十五秒", "薄纖維製品不得超過三秒", "厚纖維製品不得超過十秒", "展示用廣告板不得超過二十秒"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "83e46321b1e9", "answer_pdf_sha1": "7beed2e47fef", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00929', 'fire-eq-eng', 'fire-eq-eng-moex-100-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '某單一層之平房建築，樓地板面積為一百五十平方公尺，下列何種用途之場所即符合消防法第十三條第 一項規定「一定規模以上供公眾使用建築物」之範圍？', '["工廠", "百貨商場", "補習班", "旅館"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "83e46321b1e9", "answer_pdf_sha1": "7beed2e47fef", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
