  ('fire-eq-eng-moex-00931', 'fire-eq-eng', 'fire-eq-eng-moex-100-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '公共危險物品之室外儲槽場所，若設置防火水幕時，應沿防火水幕設有能以仰角多少度以上放水之固定 式放水槍？', '["55", "65", "75", "85"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "83e46321b1e9", "answer_pdf_sha1": "7beed2e47fef", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00932', 'fire-eq-eng', 'fire-eq-eng-moex-100-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據液化石油氣容器認可作業及管理要點，取得型式認可廠商之製造設施均應由專職人員擔任製造作業， 並應於多久時間內訓練？最低時數為何？', '["半年，四小時", "半年，八小時", "一年，四小時", "一年，八小時"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "83e46321b1e9", "answer_pdf_sha1": "7beed2e47fef", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL)
